-- ═══════════════════════════════════════════════════════════════════════════
-- VIGILUS — Identity Theft (California)
-- ═══════════════════════════════════════════════════════════════════════════

-- PC § 530.5(a) — Using Personal Identifying Information
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_008', 'VIGILUS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 530.5(a)', 'PC § 530.5(a)', 'Identity Theft — Willful Use of Personal Identifying Information', 'Prohibits every person from willfully obtaining personal identifying information of another person and using that information for any unlawful purpose, including to obtain or attempt to obtain credit, goods, services, real property, or medical information without the consent of that person. Wobbler offense — punishable as misdemeanor or felony with up to three years in state prison and fine up to $10,000.', '["Willful obtaining of personal identifying information","Use for any unlawful purpose without consent","Includes obtaining credit, goods, services, real property, medical information","Wobbler — misdemeanor or felony","Felony: 16 months, 2, or 3 years state prison","Fine up to $10,000","Each unauthorized use may constitute separate offense","Personal identifying information includes name, SSN, DOB, address, DL number, bank accounts, credit card numbers"]', '[{"section":"530.5(a)","description":"Core prohibition — willful use of personal identifying information for unlawful purpose"},{"section":"530.5(e)","description":"Sentencing — may be punished as misdemeanor or felony"}]', '["identity_theft_report","police_report","credit_report","fraud_affidavit","financial_statement","bank_records"]', '["identity-theft-fraud-audit"]', 'California DOJ / County District Attorney', 1, 1, datetime('now'), datetime('now'));

-- PC § 530.5(c) — Acquiring or Retaining Personal Identifying Information
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_009', 'VIGILUS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 530.5(c)(1)-(3)', 'PC § 530.5(c)', 'Identity Theft — Acquiring or Retaining Personal Identifying Information', 'Prohibits acquiring or retaining possession of personal identifying information of another with the intent to defraud. Subdivision (c)(1) criminalizes acquisition with intent to defraud; (c)(2) criminalizes acquisition or retention of personal identifying information of 10 or more persons; (c)(3) criminalizes trafficking in personal identifying information. Each is a wobbler offense.', '["Acquiring personal identifying information with intent to defraud","Retaining possession of personal identifying information with intent to defraud","10+ persons threshold triggers enhanced provisions under (c)(2)","Selling, transferring, or conveying personal identifying information with knowledge of unlawful use under (c)(3)","Wobbler — misdemeanor or felony for each subdivision","Felony: 16 months, 2, or 3 years state prison","Intent to defraud is required element"]', '[{"section":"530.5(c)(1)","description":"Acquiring or retaining PII with intent to defraud"},{"section":"530.5(c)(2)","description":"Acquiring or retaining PII of 10+ persons"},{"section":"530.5(c)(3)","description":"Selling, transferring, or conveying PII for unlawful use"}]', '["identity_theft_report","police_report","data_breach_records","digital_forensics_report","financial_records"]', '["identity-theft-fraud-audit"]', 'California DOJ / County District Attorney', 1, 1, datetime('now'), datetime('now'));

-- PC § 530.5(d) — Internet/Email Identity Theft
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_010', 'VIGILUS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 530.5(d)', 'PC § 530.5(d)', 'Identity Theft — Internet or Email Fraud', 'Prohibits willfully obtaining personal identifying information of another and using it to create, operate, or maintain a website, e-mail address, or social media account for the purpose of committing fraud or engaging in unlawful activity. Specifically targets online impersonation, phishing, and digital identity fraud schemes.', '["Willful obtaining of personal identifying information","Use to create or maintain website, email, or social media account","Purpose must be to commit fraud or unlawful activity","Includes phishing, online impersonation, and spoofed accounts","Wobbler — misdemeanor or felony","Felony: 16 months, 2, or 3 years state prison","Fine up to $10,000"]', '[{"section":"530.5(d)","description":"Creating or maintaining online accounts using stolen PII for fraud"},{"section":"530.5(e)","description":"Sentencing provisions"}]', '["identity_theft_report","police_report","email_records","website_records","social_media_records","digital_forensics_report"]', '["identity-theft-fraud-audit"]', 'California DOJ / County District Attorney', 1, 1, datetime('now'), datetime('now'));

-- PC § 530.6 — Identity Theft Victim Rights
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_011', 'VIGILUS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 530.6', 'PC § 530.6', 'Identity Theft Victim Rights — Law Enforcement Report', 'Establishes the right of identity theft victims to initiate a law enforcement investigation. A person who has learned or reasonably suspects that their personal identifying information has been unlawfully used may initiate a police report with their local law enforcement agency. The agency is required to take the report and provide the victim with a copy. The report may be filed in the jurisdiction where the victim resides.', '["Victim may initiate law enforcement report in jurisdiction of residence","Law enforcement agency shall take the report and provide copy to victim","Report may be filed regardless of where the identity theft occurred","Law enforcement shall not refuse to take report","Victim entitled to copy of the report","Report serves as basis for credit bureau disputes and creditor claims","Jurisdiction of residence — not limited to where crime occurred"]', '[{"section":"530.6(a)","description":"Right to file identity theft police report in jurisdiction of residence"},{"section":"530.6(b)","description":"Law enforcement duty to take report and provide copy"},{"section":"530.6(c)","description":"Report available for use with credit bureaus and creditors"}]', '["police_report","identity_theft_affidavit","victim_declaration","credit_dispute_letter","FTC_identity_theft_report"]', '["identity-theft-fraud-audit"]', 'Local Law Enforcement / California DOJ', 1, 1, datetime('now'), datetime('now'));

-- CC § 1785.11.2 — Credit Report Security Freeze
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_012', 'VIGILUS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1785.11.2', 'CC § 1785.11.2', 'Identity Theft — Credit Report Security Freeze', 'Allows any consumer to place a security freeze on their credit report by making a request to a consumer credit reporting agency. Once placed, the agency may not release the report without the consumer''s express authorization. Identity theft victims are entitled to a free freeze. The freeze must be placed within 3 business days of receiving the request and lifted within 3 business days of receiving a valid request to remove.', '["Consumer may place security freeze on credit report","Agency may not release frozen report without express authorization","Identity theft victims entitled to free freeze placement","Freeze placed within 3 business days of request","Temporary lift within 3 business days of request","Written confirmation of freeze required","PIN or password must be provided for freeze management","Violations subject to civil penalties"]', '[{"section":"1785.11.2(a)","description":"Right to place security freeze on credit report"},{"section":"1785.11.2(b)","description":"Agency prohibition on releasing frozen report"},{"section":"1785.11.2(d)","description":"3 business day placement requirement"},{"section":"1785.11.2(j)","description":"Free freeze for identity theft victims"}]', '["credit_freeze_request","credit_report","identity_theft_report","freeze_confirmation","PIN_documentation"]', '["identity-theft-fraud-audit"]', 'California Attorney General / FTC', 1, 1, datetime('now'), datetime('now'));

-- SB 1047 / PUC § 2889.5 — SIM Swap Prevention
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_013', 'VIGILUS', 'STATE_STATUTE', 'CA', 'Cal. Pub. Util. Code § 2889.5', 'PUC § 2889.5', 'SIM Swap Fraud Prevention — Wireless Carrier Obligations', 'Requires wireless telephone service providers to implement safeguards against unauthorized SIM swaps and port-out fraud. Carriers must authenticate subscriber identity before completing a SIM swap or number transfer. Enacted via SB 1047 to address the growing threat of SIM swap attacks used to intercept two-factor authentication, steal cryptocurrency, and facilitate identity theft.', '["Wireless carriers must verify subscriber identity before SIM swap","Authentication required before number port-out","Carriers must provide notification to subscriber upon SIM change","Customer may request additional security measures","Carriers must maintain records of SIM swap requests","Failure to comply subjects carrier to enforcement action","Subscribers may designate authorized contacts for account changes"]', '[{"section":"2889.5(a)","description":"Carrier duty to authenticate before SIM swap"},{"section":"2889.5(b)","description":"Subscriber notification upon SIM change"},{"section":"2889.5(c)","description":"Customer opt-in for enhanced security measures"},{"section":"2889.5(d)","description":"Carrier record-keeping requirements"}]', '["SIM_swap_complaint","carrier_records","phone_records","authentication_logs","fraud_report","account_activity_records"]', '["identity-theft-fraud-audit"]', 'California PUC / FCC', 1, 1, datetime('now'), datetime('now'));


