-- 18 USC § 1028 — Federal Identity Theft
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_014', 'VIGILUS', 'FEDERAL_STATUTE', 'US', '18 U.S.C. § 1028', '18 USC § 1028', 'Federal Identity Theft — Fraud and Related Activity in Connection with Identification Documents', 'Comprehensive federal statute criminalizing fraud and related activity involving identification documents, authentication features, and false identification documents. Prohibits knowingly producing, transferring, or possessing with intent to defraud an identification document, authentication feature, or false identification document. Penalties range up to 15 years imprisonment, or 20-30 years if used in connection with drug trafficking, violent crime, or international terrorism.', '["Producing identification document or authentication feature without authority","Transferring identification document knowing it was stolen or produced without authority","Possessing with intent to defraud five or more identification documents","Possessing identification document not rightfully issued for that person","Producing, transferring, or possessing document-making implement","Possessing, using, or transferring means of identification of another person","Enhanced penalties for connection to drug trafficking or violent crime","Up to 15 years base; 20 years if facilitating drug trafficking; 30 years if facilitating terrorism"]', '[{"section":"1028(a)(1)","description":"Producing identification document without authority"},{"section":"1028(a)(5)","description":"Possessing document-making implements"},{"section":"1028(a)(7)","description":"Possessing, transferring, or using means of identification of another"},{"section":"1028(b)","description":"Penalties — graduated by offense type and connection to other crimes"},{"section":"1028(d)","description":"Definitions — means of identification, identification document"}]', '["federal_indictment","FBI_report","identity_theft_complaint","financial_records","forged_documents","digital_forensics_report"]', '["identity-theft-fraud-audit"]', 'FBI / DOJ / US Attorney', 0, 1, datetime('now'), datetime('now'));

-- 18 USC § 1028A — Aggravated Identity Theft
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_015', 'VIGILUS', 'FEDERAL_STATUTE', 'US', '18 U.S.C. § 1028A', '18 USC § 1028A', 'Aggravated Identity Theft — Mandatory Consecutive Sentence', 'Imposes a mandatory consecutive sentence of 2 years imprisonment (5 years for terrorism offenses) for anyone who, during and in relation to any enumerated felony, knowingly transfers, possesses, or uses the means of identification of another person without lawful authority. The sentence must run consecutively to any other term of imprisonment — it cannot be served concurrently. Court may not place defendant on probation for this offense.', '["Mandatory 2-year consecutive sentence (5 years for terrorism)","Must be during and in relation to enumerated felony","Knowing transfer, possession, or use of means of identification","Of another actual person — not fictitious (Flores-Figueroa v. United States, 556 U.S. 646)","Sentence runs consecutively — cannot run concurrently","No probation permitted","Enumerated felonies include theft, fraud, immigration, passport offenses"]', '[{"section":"1028A(a)(1)","description":"2-year mandatory consecutive sentence for identity theft during enumerated felony"},{"section":"1028A(a)(2)","description":"5-year mandatory consecutive sentence for terrorism-related identity theft"},{"section":"1028A(b)","description":"Consecutive sentence requirement — may not run concurrently"},{"section":"1028A(c)","description":"Enumerated predicate felonies"}]', '["federal_indictment","sentencing_memorandum","identity_theft_complaint","financial_records","digital_forensics_report"]', '["identity-theft-fraud-audit"]', 'FBI / DOJ / US Attorney', 0, 1, datetime('now'), datetime('now'));


