-- 18 USC § 1030(a)(2) — CFAA Unauthorized Access
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_016', 'VIGILUS', 'FEDERAL_STATUTE', 'US', '18 U.S.C. § 1030(a)(2)', '18 USC § 1030(a)(2)', 'CFAA — Unauthorized Access to Obtain Information', 'Prohibits intentionally accessing a computer without authorization, or exceeding authorized access, and thereby obtaining information from any protected computer. After Van Buren v. United States, 593 U.S. 374 (2021), "exceeds authorized access" means accessing areas of the computer the person is not entitled to access — not misusing information one is authorized to obtain. Covers financial records, government information, and information from any protected computer involved in interstate commerce.', '["Intentionally accessing without authorization or exceeding authorized access","Obtaining information from protected computer","Protected computer includes any computer used in interstate/foreign commerce","Van Buren narrowed scope — must access off-limits areas, not misuse permitted access","Misdemeanor for first offense; felony if for commercial advantage, private financial gain, or furtherance of crime","Felony: up to 5 years (10 years for repeat offense)","Civil cause of action under § 1030(g) for compensatory damages and injunctive relief"]', '[{"section":"1030(a)(2)(A)","description":"Obtaining information from financial institution computer"},{"section":"1030(a)(2)(B)","description":"Obtaining information from US Government computer"},{"section":"1030(a)(2)(C)","description":"Obtaining information from any protected computer"},{"section":"1030(e)(2)","description":"Definition of protected computer"},{"section":"1030(g)","description":"Civil action for damages and injunctive relief"}]', '["digital_forensics_report","access_logs","network_logs","FBI_report","civil_complaint","damages_calculation"]', '["identity-theft-fraud-audit"]', 'FBI / DOJ / US Attorney / Private Civil Action', 1, 1, datetime('now'), datetime('now'));

-- 18 USC § 1030(a)(5) — CFAA Damage to Computer
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_017', 'VIGILUS', 'FEDERAL_STATUTE', 'US', '18 U.S.C. § 1030(a)(5)', '18 USC § 1030(a)(5)', 'CFAA — Knowingly Causing Damage to Protected Computer', 'Prohibits knowingly causing the transmission of a program, information, code, or command that intentionally causes damage to a protected computer. Covers three tiers: (A) knowing transmission causing intentional damage; (B) intentional access causing reckless damage; (C) intentional access causing damage and loss. Damage includes impairment of data integrity, availability, or system operation. Loss aggregation threshold of $5,000 in any one-year period.', '["Knowingly transmitting program/code causing intentional damage","Intentional access causing reckless damage","Intentional access causing damage and loss","Damage includes impairment of integrity or availability of data","Loss threshold: $5,000 aggregate in any 1-year period","Intentional damage: up to 10 years (20 years repeat)","Reckless damage: up to 5 years (20 years repeat)","Includes ransomware, malware, wipers, and DDoS attacks"]', '[{"section":"1030(a)(5)(A)","description":"Knowing transmission causing intentional damage"},{"section":"1030(a)(5)(B)","description":"Intentional access causing reckless damage"},{"section":"1030(a)(5)(C)","description":"Intentional access causing damage and loss"},{"section":"1030(e)(8)","description":"Definition of damage — impairment of integrity or availability"},{"section":"1030(e)(11)","description":"Definition of loss — reasonable cost of responding"}]', '["digital_forensics_report","malware_analysis","incident_response_report","access_logs","damages_assessment","FBI_report"]', '["identity-theft-fraud-audit"]', 'FBI / DOJ / US Attorney / Private Civil Action', 1, 1, datetime('now'), datetime('now'));

-- 18 USC § 1030(a)(6) — CFAA Trafficking Passwords
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_018', 'VIGILUS', 'FEDERAL_STATUTE', 'US', '18 U.S.C. § 1030(a)(6)', '18 USC § 1030(a)(6)', 'CFAA — Trafficking in Computer Passwords', 'Prohibits knowingly and with intent to defraud trafficking in any password or similar information through which a computer may be accessed without authorization, if the trafficking affects interstate or foreign commerce, or the computer is used by or for the Government of the United States. Covers sale, transfer, or distribution of stolen credentials, authentication tokens, and access codes.', '["Knowingly trafficking in passwords or similar access information","Intent to defraud required","Computer may be accessed without authorization through the trafficked information","Must affect interstate or foreign commerce or involve government computer","Includes selling credentials on dark web or criminal forums","Up to 1 year imprisonment (first offense); up to 10 years (repeat offense or government computer)","Similar information includes authentication tokens, SSH keys, API keys, session cookies"]', '[{"section":"1030(a)(6)","description":"Trafficking passwords or similar information for unauthorized computer access"},{"section":"1030(c)(2)","description":"Penalties — misdemeanor first offense, felony for repeat or government computer"},{"section":"1030(g)","description":"Civil action available"}]', '["digital_forensics_report","dark_web_intelligence","credential_dump_records","access_logs","FBI_report"]', '["identity-theft-fraud-audit"]', 'FBI / DOJ / US Attorney / Private Civil Action', 1, 1, datetime('now'), datetime('now'));

-- CA PC § 502 — Unauthorized Computer Access (California)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_vig_019', 'VIGILUS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 502', 'PC § 502', 'California Comprehensive Computer Data Access and Fraud Act', 'California''s primary computer crime statute. Prohibits knowingly accessing and without permission altering, damaging, deleting, destroying, or otherwise using any data, computer, computer system, or computer network for the purpose of devising or executing any scheme to defraud, deceive, or extort, or wrongfully controlling or obtaining money, property, or data. Broader than federal CFAA — does not require interstate nexus. Wobbler offense with civil remedy provisions.', '["Knowingly accessing without permission and altering, damaging, or destroying data","Knowingly accessing without permission any computer, system, or network","Disrupting or denying computer services to authorized user","Providing or assisting in providing means of access knowing it will be used for unauthorized purpose","Knowingly introducing contaminant (virus, worm) into any system","Taking, copying, or using data without authorization","No interstate commerce nexus required — state jurisdiction","Wobbler offense — misdemeanor or felony","Civil action for compensatory damages, injunctive relief, and other equitable relief"]', '[{"section":"502(c)(1)","description":"Altering, damaging, deleting, or destroying data"},{"section":"502(c)(2)","description":"Disrupting or denying computer services"},{"section":"502(c)(3)","description":"Unauthorized access to data"},{"section":"502(c)(6)","description":"Knowingly introducing contaminant"},{"section":"502(c)(7)","description":"Unauthorized copying of data"},{"section":"502(e)","description":"Civil remedy — compensatory damages and injunctive relief"}]', '["digital_forensics_report","police_report","access_logs","civil_complaint","damages_calculation","incident_response_report"]', '["identity-theft-fraud-audit"]', 'California DOJ / County DA / Private Civil Action', 1, 1, datetime('now'), datetime('now'));


